def assess(record: dict) -> str:
    required = {'business_rule', 'case_id', 'extra_policy', 'json_schema', 'valid_fixture'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (record["extra_policy"] == "allow" and not record["business_rule"])
    return "PASS" if ok else "REJECT_SCHEMA"

valid = {"case_id": 'CASO-CUS-042-1A', **{'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True}}
invalid = {"case_id": 'CASO-CUS-042-1A', **{'extra_policy': 'forbid', 'json_schema': False, 'valid_fixture': True, 'business_rule': True}}
incomplete = {k: v for k, v in valid.items() if k != 'business_rule'}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

